CREATE TABLE `asu_tuition_rate_type` (
  `id` int(10) UNSIGNED NOT NULL COMMENT 'ID',
  `rate_type` char(3) NOT NULL COMMENT 'Rate type',
  `descr` varchar(255) NOT NULL COMMENT 'Description',
  `program_fee_dropdown` tinyint(4) NOT NULL DEFAULT '0' COMMENT 'Program Fee Dropdown?',
  `weight` tinyint(4) NOT NULL COMMENT 'Weight',
  `query_string` text COMMENT 'Query string'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='ASU tuition rate types';

--
