INSERT INTO `asu_tuition_rate_type` (`id`, `rate_type`, `descr`, `program_fee_dropdown`, `weight`, `query_string`) VALUES
(1, 'F1', 'Financial Aid Trust Fee', 0, 2, 'SELECT DISTINCT\r\n  fc.fee_code,\r\n  fc.descr,\r\n  fc.note,\r\n  fr.enrlld_hrs,\r\n  fr.fee_rate,\r\n  fr.fee_type\r\nFROM asu_tuition_fee_code AS fc\r\nLEFT JOIN asu_tuition_fee_rate AS fr USING (fee_code, fee_type)\r\nWHERE fc.fee_type LIKE \'F1\'\r\n  AND fc.campus LIKE :campus\r\n  AND fr.acad_year LIKE :acad_year\r\n  AND fr.strm LIKE :strm\r\n  AND fc.acad_prog LIKE \'\'\r\n  AND (\r\n    LENGTH(:corporate_partner) = 0\r\n    OR (\r\n      LENGTH(:corporate_partner) <> 0\r\n      AND EXISTS(\r\n        SELECT \'X\'\r\n        FROM asu_tuition_fee_rate AS fr_ex\r\n        WHERE fr_ex.fee_code = fr.fee_code\r\n          AND fr_ex.fee_type = fr.fee_type\r\n          AND fr_ex.acad_year = fr.acad_year\r\n          AND fr_ex.strm = fr.strm\r\n          AND fr_ex.fee_rate > 0\r\n      )\r\n    )\r\n  )\r\nORDER BY fr.enrlld_hrs'),
(2, 'F2', 'Recreation Fee', 0, 2, 'SELECT DISTINCT\r\n  fc.fee_code,\r\n  fc.descr,\r\n  fc.note,\r\n  fr.enrlld_hrs,\r\n  fr.fee_rate,\r\n  fr.fee_type\r\nFROM asu_tuition_fee_code AS fc\r\nLEFT JOIN asu_tuition_fee_rate AS fr USING (fee_code, fee_type)\r\nWHERE fc.fee_type LIKE \'F2\'\r\n  AND fc.campus LIKE :campus\r\n  AND fr.acad_year LIKE :acad_year\r\n  AND fr.strm LIKE :strm\r\n  AND fc.acad_prog LIKE \'\'\r\n  AND :program_fee NOT IN (\'UP0036\')\r\n  AND (\r\n    LENGTH(:corporate_partner) = 0\r\n    OR (\r\n      LENGTH(:corporate_partner) <> 0\r\n      AND EXISTS(SELECT \'X\'\r\n        FROM asu_tuition_fee_rate AS fr_ex\r\n        WHERE fr_ex.fee_code = fr.fee_code\r\n          AND fr_ex.fee_type = fr.fee_type\r\n          AND fr_ex.acad_year = fr.acad_year\r\n          AND fr_ex.strm = fr.strm\r\n          AND fr_ex.fee_rate > 0\r\n      )\r\n    )\r\n  )\r\nORDER BY fr.enrlld_hrs'),
(3, 'F3', 'Arizona Student Assoc. Fee', 0, 2, 'SELECT DISTINCT\r\n  fc.fee_code,\r\n  fc.descr,\r\n  fc.note,\r\n  fr.enrlld_hrs,\r\n  fr.fee_rate,\r\n  fr.fee_type\r\nFROM asu_tuition_fee_code AS fc\r\nLEFT JOIN asu_tuition_fee_rate AS fr USING (fee_code, fee_type)\r\nWHERE fc.fee_type LIKE \'F3\'\r\n  AND fc.campus LIKE :campus\r\n  AND fr.acad_year LIKE :acad_year\r\n  AND fr.strm LIKE :strm\r\n  AND fc.acad_prog LIKE \'\'\r\n  AND :program_fee NOT IN (\'UP0036\')\r\n  AND (\r\n    LENGTH(:corporate_partner) = 0\r\n    OR (\r\n      LENGTH(:corporate_partner) <> 0\r\n      AND EXISTS(\r\n        SELECT \'X\'\r\n        FROM asu_tuition_fee_rate AS fr_ex\r\n        WHERE fr_ex.fee_code = fr.fee_code\r\n          AND fr_ex.fee_type = fr.fee_type\r\n          AND fr_ex.acad_year = fr.acad_year\r\n          AND fr_ex.strm = fr.strm\r\n          AND fr_ex.fee_rate > 0\r\n      )\r\n    )\r\n  )\r\nORDER BY fr.enrlld_hrs'),
(4, 'F4', 'Technology Fee', 0, 2, 'SELECT DISTINCT\r\n  fc.fee_code,\r\n  fc.descr,\r\n  fc.note,\r\n  fr.enrlld_hrs,\r\n  fr.fee_rate,\r\n  fr.fee_type\r\nFROM asu_tuition_fee_code AS fc\r\nLEFT JOIN asu_tuition_fee_rate AS fr USING (fee_code, fee_type)\r\nWHERE fc.fee_type LIKE \'F4\'\r\n  AND fc.campus LIKE :campus\r\n  AND fr.acad_year LIKE :acad_year\r\n  AND fr.strm LIKE :strm\r\n  AND fc.acad_prog LIKE \'\'\r\n  /* Narrow down by career for GRAD and LAW after 2020. */\r\n  AND (\r\n    :acad_year < \'2021\'\r\n    OR fc.acad_career LIKE :acad_career\r\n  )\r\n  AND (\r\n    LENGTH(:corporate_partner) = 0\r\n    OR (\r\n      LENGTH(:corporate_partner) <> 0\r\n      AND EXISTS(\r\n        SELECT \'X\'\r\n        FROM asu_tuition_fee_rate AS fr_ex\r\n        WHERE fr_ex.fee_code = fr.fee_code\r\n          AND fr_ex.fee_type = fr.fee_type\r\n          AND fr_ex.acad_year = fr.acad_year\r\n          AND fr_ex.strm = fr.strm\r\n          AND fr_ex.fee_rate > 0\r\n      )\r\n    )\r\n  )\r\n  /* Removed per SFAODEV-584 */\r\n  AND :program_fee NOT IN (\'GS0001\')\r\nORDER BY fr.enrlld_hrs'),
(5, 'F5', 'Student Programs Fees', 0, 2, 'SELECT DISTINCT\r\n  fc.fee_code,\r\n  fc.descr,\r\n  fc.note,\r\n  fr.enrlld_hrs,\r\n  fr.fee_rate,\r\n  fr.fee_type\r\nFROM asu_tuition_fee_code AS fc\r\nLEFT JOIN asu_tuition_fee_rate AS fr USING (fee_code, fee_type)\r\nWHERE fc.fee_type LIKE \'F5\'\r\n  AND fc.campus LIKE :campus\r\n  AND fc.acad_career LIKE (\r\n    CASE\r\n      WHEN :acad_career = \'UGRDN\'\r\n      THEN \'UGRD\'\r\n      ELSE :acad_career\r\n    END\r\n  )\r\n  AND fr.acad_year LIKE :acad_year\r\n  AND fr.strm LIKE :strm\r\n  AND fc.acad_prog LIKE \'\'\r\n  AND :program_fee NOT IN (\'UP0036\')\r\n  AND (\r\n    LENGTH(:corporate_partner) = 0\r\n    OR (\r\n      LENGTH(:corporate_partner) <> 0\r\n      AND EXISTS(\r\n        SELECT \'X\'\r\n        FROM asu_tuition_fee_rate AS fr_ex\r\n        WHERE fr_ex.fee_code = fr.fee_code\r\n          AND fr_ex.fee_type = fr.fee_type\r\n          AND fr_ex.acad_year = fr.acad_year\r\n          AND fr_ex.strm = fr.strm\r\n          AND fr_ex.fee_rate > 0\r\n      )\r\n    )\r\n  )\r\nORDER BY fr.enrlld_hrs'),
(6, 'F6', 'Health and Wellness Fee', 0, 2, 'SELECT DISTINCT\r\n  fc.fee_code,\r\n  fc.descr,\r\n  fc.note,\r\n  fr.enrlld_hrs,\r\n  fr.fee_rate,\r\n  fr.fee_type\r\nFROM asu_tuition_fee_code AS fc\r\nLEFT JOIN asu_tuition_fee_rate AS fr USING (fee_code, fee_type)\r\nWHERE fc.fee_type LIKE \'F6\'\r\n  AND fc.campus LIKE :campus\r\n  AND fr.acad_year LIKE :acad_year\r\n  AND fr.strm LIKE :strm\r\n  AND fc.acad_prog LIKE \'\'\r\n  AND :program_fee NOT IN (\'UP0036\')\r\n  AND (\r\n    LENGTH(:corporate_partner) = 0\r\n    OR (\r\n      LENGTH(:corporate_partner) <> 0\r\n      AND EXISTS(\r\n        SELECT \'X\'\r\n        FROM asu_tuition_fee_rate AS fr_ex\r\n        WHERE fr_ex.fee_code = fr.fee_code\r\n          AND fr_ex.fee_type = fr.fee_type\r\n          AND fr_ex.acad_year = fr.acad_year\r\n          AND fr_ex.strm = fr.strm\r\n          AND fr_ex.fee_rate > 0\r\n      )\r\n    )\r\n  )\r\nORDER BY fr.enrlld_hrs'),
(7, 'F7', 'Student Services Facility Fee', 0, 2, 'SELECT DISTINCT\r\n  fc.fee_code,\r\n  fc.descr,\r\n  fc.note,\r\n  fr.enrlld_hrs,\r\n  fr.fee_rate,\r\n  fr.fee_type\r\nFROM asu_tuition_fee_code AS fc\r\nLEFT JOIN asu_tuition_fee_rate AS fr USING (fee_code, fee_type)\r\nWHERE fc.fee_type LIKE \'F7\'\r\n  AND fc.campus LIKE :campus\r\n  AND fr.acad_year LIKE :acad_year\r\n  AND fr.strm LIKE :strm\r\n  AND fc.acad_prog LIKE \'\'\r\n  AND :program_fee NOT IN (\'UP0036\')\r\n  AND (\r\n    LENGTH(:corporate_partner) = 0\r\n    OR (\r\n      LENGTH(:corporate_partner) <> 0\r\n      AND EXISTS(\r\n        SELECT \'X\'\r\n        FROM asu_tuition_fee_rate AS fr_ex\r\n        WHERE fr_ex.fee_code = fr.fee_code\r\n          AND fr_ex.fee_type = fr.fee_type\r\n          AND fr_ex.acad_year = fr.acad_year\r\n          AND fr_ex.strm = fr.strm\r\n          AND fr_ex.fee_rate > 0\r\n      )\r\n    )\r\n  )\r\nORDER BY fr.enrlld_hrs'),
(8, 'F8', 'W.P. Carey School of Business Majors Facility Fee', 0, 2, 'SELECT DISTINCT\n  fc.fee_code,\n  fc.descr,\n  fc.note,\n  fr.enrlld_hrs,\n  fr.fee_rate,\n  fr.fee_type\nFROM asu_tuition_fee_code AS fc\nLEFT JOIN asu_tuition_fee_rate AS fr USING (fee_code, fee_type)\nWHERE fc.fee_type LIKE \'F8\'\n  AND fc.campus LIKE :campus\n  AND fr.acad_year LIKE :acad_year\n  AND fr.strm LIKE :strm\n  AND fc.acad_prog LIKE :acad_prog\n  AND (\n    LENGTH(:corporate_partner) = 0\n    OR (\n      LENGTH(:corporate_partner) <> 0\n      AND EXISTS(\n        SELECT \'X\'\n        FROM asu_tuition_fee_rate AS fr_ex\n        WHERE fr_ex.fee_code = fr.fee_code\n          AND fr_ex.fee_type = fr.fee_type\n          AND fr_ex.acad_year = fr.acad_year\n          AND fr_ex.strm = fr.strm\n          AND fr_ex.fee_rate > 0\n      )\n    )\n  )\nORDER BY fr.enrlld_hrs'),
(9, 'P1', 'Program Fee', 1, 1, 'SELECT DISTINCT\r\n  fc.fee_code,\r\n  \'Program Fee\' AS descr,\r\n  fc.note,\r\n  fr.enrlld_hrs,\r\n  fr.fee_rate,\r\n  fr.fee_type\r\nFROM asu_tuition_fee_code AS fc\r\nLEFT JOIN asu_tuition_fee_rate AS fr USING (fee_code, fee_type)\r\nWHERE fc.fee_type LIKE \'P1\'\r\n  AND fc.fee_code LIKE :program_fee\r\n  AND fr.acad_year LIKE :acad_year\r\n  AND fr.strm LIKE :strm\r\nORDER BY fr.enrlld_hrs'),
(10, 'P2', 'Honors Program Tuition', 0, 1, 'SELECT DISTINCT\r\n  fc.fee_code,\r\n  fc.descr,\r\n  fc.note,\r\n  fr.enrlld_hrs,\r\n  fr.fee_rate\r\nFROM asu_tuition_fee_code AS fc\r\nJOIN (\r\n  SELECT ayt.id, ayt.acad_year, ayt.descr, ayt.fall_term AS strm FROM asu_tuition_acad_year ayt\r\n  UNION\r\n  SELECT ayt.id, ayt.acad_year, ayt.descr, ayt.spring_term AS strm FROM asu_tuition_acad_year ayt\r\n  UNION\r\n  SELECT ayt.id, ayt.acad_year, ayt.descr, ayt.summer_term AS strm FROM asu_tuition_acad_year ayt\r\n) AS ay\r\nJOIN asu_tuition_acad_career AS ac ON (ac.acad_career LIKE IF(:acad_career = \'UGRDN\', \'UGRD\', :acad_career))\r\nJOIN (\r\n  SELECT at.admit_term AS strm, \r\n  MIN(\r\n    CASE\r\n      WHEN :admit_term = \'\' AND :admit_level = \'\'\r\n      THEN \'9999\'\r\n      WHEN :acad_career = \'GRAD\'\r\n      THEN tg.admit_term\r\n      WHEN tg.end_term >= at.admit_term\r\n      THEN tg.base_term\r\n      ELSE \'9999\'\r\n    END\r\n  ) AS base_term\r\n  FROM asu_tuition_tuition_group tg\r\n  JOIN asu_tuition_admit_term at\r\n  WHERE tg.admit_term = IF(:admit_term <> \'\', :admit_term, tg.admit_term)\r\n  AND tg.acad_level = IF(:admit_level <> \'\', :admit_level, tg.acad_level)\r\n  GROUP BY at.admit_term\r\n) AS bt ON (bt.strm = ay.strm)\r\nLEFT JOIN asu_tuition_fee_rate AS fr USING (fee_code, fee_type)\r\nWHERE ay.acad_year = :acad_year\r\nAND ay.strm = :strm\r\nAND fc.fee_type LIKE \'P2\'\r\n  AND fc.campus LIKE :campus\r\n  AND fc.residency LIKE :residency\r\n  AND fc.acad_career LIKE ac.acad_career\r\n  AND (\r\n    fc.base_term LIKE bt.base_term\r\n    OR fc.base_term = \'\'\r\n  )\r\n  AND fr.acad_year LIKE :acad_year\r\n  AND fr.strm LIKE :strm\r\n  AND fc.acad_prog = \'\'\r\n  AND :honors = 1\r\nORDER BY fr.enrlld_hrs'),
(11, 'P3', 'Differential Tuition', 1, 1, ''),
(12, 'P4', 'Approved Programs On Hold', 0, 1, ''),
(13, 'T1', 'Base Tuition', 0, 0, 'SELECT DISTINCT\r\n  fc.fee_code,\r\n  CONCAT((SELECT DISTINCT r.descr FROM asu_tuition_residency r WHERE r.residency = :residency), IF(:campus = \'ONLNE\', \' Online\', \'\'), \' Tuition\') AS descr,\r\n  fc.note,\r\n  fr.enrlld_hrs,\r\n  fr.fee_rate + COALESCE((\r\n    SELECT DISTINCT fr3.fee_rate\r\n    FROM asu_tuition_fee_code AS fc3\r\n    LEFT JOIN asu_tuition_fee_rate AS fr3 USING (fee_code, fee_type)\r\n    WHERE fc3.fee_type = \'P3\'\r\n      AND fc3.fee_code LIKE :program_fee\r\n      AND fr3.acad_year LIKE fr.acad_year\r\n      AND fr3.strm LIKE fr.strm\r\n      AND fr3.enrlld_hrs = fr.enrlld_hrs\r\n  ), 0) AS fee_rate\r\nFROM asu_tuition_fee_code AS fc\r\nJOIN (\r\n  SELECT ayt.id, ayt.acad_year, ayt.descr, ayt.fall_term AS strm FROM asu_tuition_acad_year ayt\r\n  UNION\r\n  SELECT ayt.id, ayt.acad_year, ayt.descr, ayt.spring_term AS strm FROM asu_tuition_acad_year ayt\r\n  UNION\r\n  SELECT ayt.id, ayt.acad_year, ayt.descr, ayt.summer_term AS strm FROM asu_tuition_acad_year ayt\r\n) AS ay\r\nJOIN asu_tuition_acad_career AS ac ON (ac.acad_career LIKE IF(:acad_career = \'UGRDN\', \'UGRD\', :acad_career))\r\nJOIN (\r\n  SELECT at.admit_term AS strm, \r\n  MIN(\r\n    CASE\r\n      WHEN :acad_year >= \'2020\' AND :admit_level <> \'\'\r\n      THEN (\r\n        SELECT MIN(fayt.fall_term)\r\n        FROM asu_tuition_acad_year fayt\r\n        WHERE fayt.acad_year = :acad_year\r\n      )\r\n      WHEN (:admit_term = \'\' AND :admit_level = \'\') OR (at.admit_term < :admit_term)\r\n      THEN \'9999\'\r\n      WHEN :acad_career = \'GRAD\'\r\n      THEN tg.admit_term\r\n      WHEN tg.end_term >= at.admit_term\r\n      THEN tg.base_term\r\n      ELSE \'9999\'\r\n    END\r\n  ) AS base_term\r\n  FROM asu_tuition_tuition_group tg\r\n  JOIN asu_tuition_admit_term at\r\n  WHERE tg.admit_term = IF(:admit_term <> \'\', :admit_term, tg.admit_term)\r\n  AND tg.acad_level = IF(:admit_level <> \'\', :admit_level, tg.acad_level)\r\n  GROUP BY at.admit_term\r\n) AS bt ON (bt.strm = ay.strm)\r\nJOIN (\r\n  SELECT DISTINCT COALESCE(\r\n    (\r\n      SELECT CASE \r\n        WHEN :acad_year <= \'2019\'\r\n        THEN FLOOR((COUNT(*) - 1) / 3) * 10\r\n        ELSE 0\r\n        END\r\n      FROM asu_tuition_admit_term att\r\n      WHERE att.admit_term BETWEEN :admit_term AND :strm),\r\n    0) + IF(:admit_level <> \'\', CAST(:admit_level AS SIGNED INTEGER), 0) AS commitment_level\r\n  FROM DUAL\r\n) AS cl\r\nLEFT JOIN asu_tuition_fee_rate AS fr USING (fee_code, fee_type)\r\nWHERE ay.acad_year = :acad_year\r\nAND ay.strm = :strm\r\nAND fc.campus LIKE :campus\r\nAND fc.residency LIKE :residency\r\nAND fc.acad_career LIKE ac.acad_career\r\nAND fr.acad_year LIKE :acad_year\r\nAND fr.strm LIKE :strm\r\nAND (\r\n  (\r\n    :program_fee NOT IN (\'UP0036\', \'USO003\', \'GP0084\', \'GP0103\', \'US0001\', \'US0002\', \'US0003\', \'US0004\', \'GS0001\', \'UPO101\', \'GP0231\', \'GP0346\', \'GP0347\', \'GP0269\', \'GP0285\',\'GP0342\',\'GP0343\')\r\n    AND fc.fee_type LIKE \'T1\'\r\n    AND (\r\n      (\r\n        /* Tuition discount exists and student is sophomore or less. */\r\n        EXISTS(\r\n          SELECT fc_count.fee_code\r\n          FROM asu_tuition_fee_code AS fc_count\r\n          LEFT JOIN asu_tuition_fee_rate AS fr_count USING (fee_code, fee_type)\r\n          WHERE fc_count.fee_type LIKE \'T1\'\r\n          AND fc_count.campus LIKE :campus\r\n          AND fc_count.residency LIKE :residency\r\n          AND fc_count.acad_career LIKE ac.acad_career\r\n          AND fc_count.base_term LIKE bt.base_term\r\n          AND fr_count.acad_year LIKE :acad_year\r\n          AND fr_count.strm LIKE :strm\r\n          AND fc_count.acad_prog LIKE :acad_prog)\r\n        AND cl.commitment_level <= 20\r\n        AND fc.acad_prog = :acad_prog\r\n        AND fc.base_term LIKE bt.base_term\r\n      )\r\n      OR (\r\n        /* All other students. */\r\n        (\r\n          NOT EXISTS(\r\n            SELECT fc_count.fee_code\r\n            FROM asu_tuition_fee_code AS fc_count\r\n            LEFT JOIN asu_tuition_fee_rate AS fr_count USING (fee_code, fee_type)\r\n            WHERE fc_count.fee_type LIKE \'T1\'\r\n            AND fc_count.campus LIKE :campus\r\n            AND fc_count.residency LIKE :residency\r\n            AND fc_count.acad_career LIKE ac.acad_career\r\n            AND fc_count.base_term LIKE bt.base_term\r\n            AND fr_count.acad_year LIKE :acad_year\r\n            AND fr_count.strm LIKE :strm\r\n            AND fc_count.acad_prog LIKE :acad_prog)\r\n          OR cl.commitment_level > 20\r\n        )    \r\n        AND fc.acad_prog = \'\'\r\n        AND (\r\n          fc.base_term LIKE IF(cl.commitment_level > 20, \'9999\', bt.base_term)\r\n          OR fc.base_term = \'\'\r\n        )\r\n      )\r\n    )\r\n  )\r\n  OR (\r\n    /* Exceptions for special tuition rates. */\r\n    /* Excluded GS0001 per SFAODEV-584 */\r\n    :program_fee IN (\'UP0036\', \'USO003\', \'GP0084\', \'GP0103\', \'US0001\', \'US0002\', \'US0003\', \'US0004\', /* \'GS0001\', */ \'UPO101\', \'GP0231\', \'GP0346\', \'GP0347\', \'GP0269\', \'GP0285\',\'GP0342\',\'GP0343\')\r\n    AND (\r\n      (:admit_term = \'\'\r\n        AND fc.base_term = \'\'\r\n      )\r\n      OR (:admit_term <> \'\'\r\n        AND fc.base_term LIKE bt.base_term\r\n      )\r\n    )\r\n    AND (\r\n      fc.fee_type LIKE \'T4\'\r\n      OR fc.fee_type LIKE \'T3\'\r\n    )\r\n  )\r\n)\r\nORDER BY fr.enrlld_hrs'),
(14, 'T2', 'Resident Surcharge', 0, 0, 'SELECT DISTINCT\r\n  fc.fee_code, \r\n  fc.descr, \r\n  fc.note, \r\n  fr.enrlld_hrs, \r\n  fr.fee_rate, \r\n  fr.fee_type\r\nFROM asu_tuition_fee_code AS fc\r\nLEFT JOIN asu_tuition_fee_rate AS fr USING (fee_code, fee_type)\r\nWHERE fc.fee_type = \'T2\'\r\n  AND :campus NOT IN (\'ONLNE\', \'WASHD\', \'LOSAN\', \'CALHC\')\r\n  AND fc.residency LIKE :residency\r\n  AND fr.acad_year LIKE :acad_year\r\n  AND fr.strm LIKE :strm\r\nORDER BY fr.enrlld_hrs'),
(15, 'T3', 'Special Online Tuition', 0, 0, 'SELECT DISTINCT\r\n  fc.fee_code, \r\n  fc.descr, \r\n  fc.note, \r\n  fr.enrlld_hrs, \r\n  fr.fee_rate, \r\n  fr.fee_type\r\nFROM asu_tuition_fee_code AS fc\r\nLEFT JOIN asu_tuition_fee_rate AS fr USING (fee_code, fee_type)\r\nWHERE fc.fee_type LIKE \'T3\'\r\n  AND fc.fee_code LIKE :program_fee\r\n  AND fr.acad_year LIKE :acad_year\r\n  AND fr.strm LIKE :strm\r\n  AND :campus IN (\'ONLNE\', \'LOSAN\',\'WASHD\')\r\nORDER BY fr.enrlld_hrs'),
(16, 'T4', 'Special Program Tuition', 0, 0, ''),
(17, 'F9', 'Athletics Fee', 0, 2, 'SELECT DISTINCT\r\n  fc.fee_code,\r\n  fc.descr,\r\n  fc.note,\r\n  fr.enrlld_hrs,\r\n  fr.fee_rate,\r\n  fr.fee_type\r\nFROM asu_tuition_fee_code AS fc\r\nLEFT JOIN asu_tuition_fee_rate AS fr USING (fee_code, fee_type)\r\nWHERE fc.fee_type LIKE \'F9\'\r\n  AND fc.campus LIKE :campus\r\n  AND fr.acad_year LIKE :acad_year\r\n  AND fr.strm LIKE :strm\r\n  AND fc.acad_prog LIKE \'\'\r\n  AND :program_fee NOT IN (\'UP0036\')\r\n  AND (\r\n    LENGTH(:corporate_partner) = 0\r\n    OR (\r\n      LENGTH(:corporate_partner) <> 0\r\n      AND EXISTS(\r\n        SELECT \'X\'\r\n        FROM asu_tuition_fee_rate AS fr_ex\r\n        WHERE fr_ex.fee_code = fr.fee_code\r\n          AND fr_ex.fee_type = fr.fee_type\r\n          AND fr_ex.acad_year = fr.acad_year\r\n          AND fr_ex.strm = fr.strm\r\n          AND fr_ex.fee_rate > 0\r\n      )\r\n    )\r\n  )\r\nORDER BY fr.enrlld_hrs'),
(18, 'C1', 'Coaching Fee', 0, 2, ''),
